function uid() {
  return globalThis.crypto?.randomUUID?.() || `id-${Date.now()}-${Math.random().toString(36).slice(2)}`;
}
function today() { return new Date().toISOString().slice(0, 10); }
function dateFromToday(days) { const date = new Date(); date.setDate(date.getDate() + days); return date.toISOString().slice(0, 10); }
function daysUntil(date) { return date ? Math.ceil((new Date(date).getTime() - new Date(today()).getTime()) / 86400000) : null; }
function deepClone(value) { return JSON.parse(JSON.stringify(value)); }
function normalizeHeader(value) { return String(value || "").toLowerCase().trim().replace(/[^a-z0-9]+/g, ""); }
function safeFileName(name) { return name.normalize("NFKD").replace(/[^a-zA-Z0-9._-]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 140) || "evidence"; }
function createRecordId() { const stamp = today().replaceAll("-", ""); return `NMA-${stamp}-${Math.random().toString(36).slice(2, 6).toUpperCase()}`; }

function parseDelimited(text) {
  const rows = [];
  const delimiter = text.includes("\t") ? "\t" : ",";
  let row = [], cell = "", quoted = false;
  for (let index = 0; index < text.length; index += 1) {
    const character = text[index];
    if (character === '"') {
      if (quoted && text[index + 1] === '"') { cell += '"'; index += 1; }
      else quoted = !quoted;
    } else if (character === delimiter && !quoted) { row.push(cell.trim()); cell = ""; }
    else if ((character === "\n" || character === "\r") && !quoted) {
      if (character === "\r" && text[index + 1] === "\n") index += 1;
      row.push(cell.trim()); if (row.some((value) => value !== "")) rows.push(row); row = []; cell = "";
    } else cell += character;
  }
  row.push(cell.trim()); if (row.some((value) => value !== "")) rows.push(row);
  return rows;
}

function blankInstrument() {
  return {
    id: uid(), gageId: "", name: "", type: "Micrometer", manufacturer: "", model: "", serialNumber: "",
    department: "", location: "Controlled Storage", owner: "", assignedTo: "", workCenter: "", range: "", resolution: "",
    accuracy: "", frequencyDays: 365, calibrationMethod: "external", vendor: "", lastCalibration: "", nextDue: "",
    status: "available", criticality: "moderate", backupAvailable: true, productProcess: "", environmentalRequirements: "",
    restrictions: "", photoName: "", photoDataUrl: "", documentNames: [], history: [], archived: false,
  };
}
function blankCalibration(instrumentId = "") {
  return { id: uid(), instrumentId, calibrationDate: today(), technician: "", laboratory: "", standardTraceability: "", environment: "", asFound: "", adjustment: "", asLeft: "", result: "pass", certificateNumber: "", certificateNames: [], releaseAuthority: "", nextDue: "", note: "", history: [] };
}
function blankVerification(instrumentId = "") {
  return { id: uid(), instrumentId, verificationDate: today(), method: "Before-use reference check", referenceStandard: "", acceptanceCriteria: "", result: "pass", performedBy: "", note: "", evidenceNames: [], history: [] };
}
function blankCustody(instrumentId = "") {
  return { id: uid(), instrumentId, transactionDate: new Date().toISOString(), fromLocation: "", toLocation: "Production Floor", recipient: "", jobWorkOrder: "", condition: "Acceptable", expectedReturn: "", note: "", history: [] };
}
function blankOot(instrumentId = "") {
  return { id: uid(), instrumentId, discoveredDate: today(), source: "Calibration failure", lastKnownAcceptable: "", riskStartDate: "", affectedJobs: "", affectedLots: "", affectedCustomers: "", severity: "high", containment: "", reinspectionPlan: "", productDecision: "", equipmentDisposition: "quarantined", linkedNcr: "", linkedCapa: "", owner: "", status: "open", closureAuthority: "", effectiveness: "", evidenceNames: [], history: [] };
}
function blankMsa(instrumentId = "") {
  return { id: uid(), instrumentId, studyDate: today(), studyType: "gage_rr", characteristic: "", tolerance: "", operators: 3, parts: 10, trials: 3, percentGRR: 0, ndc: 0, result: "pending", conclusion: "", action: "", technicalApprover: "", reviewDate: dateFromToday(365), evidenceNames: [], history: [] };
}

function derivedStatus(instrument) {
  if (instrument.archived) return "retired";
  if (["quarantined", "out_of_tolerance", "lost", "retired", "out_for_calibration", "awaiting_certificate", "restricted"].includes(instrument.status)) return instrument.status;
  const due = daysUntil(instrument.nextDue);
  if (due !== null && due < 0) return "overdue";
  if (due !== null && due <= 30) return "due_soon";
  return instrument.status || "available";
}

